const rateLimitKey = 'twitter_search_rate_limit';
const storedData = JSON.parse($execution.customData.get(rateLimitKey) || 'null');
const rateLimitData = storedData || {remaining: 300, reset: Date.now() + (15 * 60 * 1000)};

if (Date.now() > rateLimitData.reset) {
  rateLimitData.remaining = 300;
  rateLimitData.reset = Date.now() + (15 * 60 * 1000);
}
if (rateLimitData.remaining <= 5) {
  const waitMinutes = Math.ceil((rateLimitData.reset - Date.now()) / 60000);
  throw new Error(`Rate limit low (${rateLimitData.remaining} remaining). Waiting ${waitMinutes} minutes.`);
}
rateLimitData.remaining -= 1;

$execution.customData.set(rateLimitKey, JSON.stringify(rateLimitData));

return [{json: {quota_remaining: rateLimitData.remaining, quota_reset_at: new Date(rateLimitData.reset).toISOString()}}];

const response = $input.item.json;
if (!response.data || response.data.length === 0) { return []; }
const tweets = response.data;
const users = response.includes?.users || [];
const userMap = {};
users.forEach(user => { userMap[user.id] = user; });
const parsedTweets = tweets.map(tweet => {
  const author = userMap[tweet.author_id] || {};
  const urls = tweet.entities?.urls?.map(u => u.expanded_url || u.url) || [];
  const hashtags = tweet.entities?.hashtags?.map(h => h.tag) || [];
  const mentions = tweet.entities?.mentions?.map(m => m.username) || [];
  const isReply = tweet.referenced_tweets?.some(rt => rt.type === 'replied_to') || false;
  const isQuote = tweet.referenced_tweets?.some(rt => rt.type === 'quoted') || false;
  const replyToId = tweet.referenced_tweets?.find(rt => rt.type === 'replied_to')?.id;
  return {
    platform: 'twitter', external_id: tweet.id, text_content: tweet.text, language: tweet.lang, created_at: tweet.created_at,
    author_username: author.username || 'unknown', author_id: tweet.author_id, author_verified: author.verified || false,
    author_followers_count: author.public_metrics?.followers_count || 0, author_description: author.description || null,
    likes_count: tweet.public_metrics?.like_count || 0, shares_count: tweet.public_metrics?.retweet_count || 0,
    replies_count: tweet.public_metrics?.reply_count || 0, views_count: tweet.public_metrics?.impression_count || 0,
    urls: urls, hashtags: hashtags, mentions: mentions, has_media: (tweet.entities?.media && tweet.entities.media.length > 0) || false,
    is_reply: isReply, is_quote: isQuote, reply_to_id: replyToId || null, conversation_id: tweet.conversation_id || null, raw_data: tweet
  };
});
return parsedTweets.map(tweet => ({ json: tweet }));

const items = $input.all();

const storedData = $execution.customData.get('processedTwitterIds');
const processedIds = new Set(storedData ? JSON.parse(storedData) : []);

const newTweets = [];
for (const item of items) {
  const externalId = item.json.external_id;
  // Bypass deduplication if tweet text contains "#FORCE" for testing
  if (!processedIds.has(externalId) || (item.json.text_content && item.json.text_content.includes('#FORCE'))) { 
    newTweets.push(item); 
    processedIds.add(externalId); 
  }
}

if (processedIds.size > 10000) {
  const idsArray = Array.from(processedIds);
  processedIds.clear();
  idsArray.slice(-10000).forEach(id => processedIds.add(id));
}

$execution.customData.set('processedTwitterIds', JSON.stringify(Array.from(processedIds)));

if (newTweets.length === 0) {
    console.log('⛔ Stopping execution: All ' + items.length + ' tweets were duplicates.');
} else {
    console.log('✅ Processing ' + newTweets.length + ' new tweets.');
}

return newTweets;

const items = $input.all();
const analyzedItems = [];

// Get Dynamic Keywords from 'Prepare Config' node
// Note: In n8n v1+, use $('NodeName').first().json
let dbKeywords = [];
try {
    const configNode = $('Prepare Config');
    if (configNode && configNode.first()) {
        dbKeywords = configNode.first().json.keywords || [];
    }
} catch (e) {
    console.log('Could not load dynamic keywords: ' + e.message);
}

// Build keyword maps
const criticalKeywords = {};
const highKeywords = {};
const mediumKeywords = {};
const lowKeywords = {};

// Defaults if DB is empty
if (!dbKeywords || dbKeywords.length === 0) {
    criticalKeywords['ransomware'] = 30;
    criticalKeywords['data breach'] = 30;
    criticalKeywords['zero-day'] = 30;
    highKeywords['phishing'] = 20;
    highKeywords['malware'] = 20;
    mediumKeywords['ciberataque'] = 15;
} else {
    dbKeywords.forEach(k => {
        const text = k.keyword_text.toLowerCase();
        const weight = k.keyword_weight || 10;
        const cat = k.keyword_category || 'medium';

        if (cat === 'critical') criticalKeywords[text] = weight;
        else if (cat === 'high') highKeywords[text] = weight;
        else if (cat === 'medium') mediumKeywords[text] = weight;
        else lowKeywords[text] = weight;
    });
}

for (const item of items) {
  const tweet = item.json;

  // Ensure sentiment structure exists
  const sentiment = tweet.sentiment || {
      vader: {},
      textblob: {},
      ensemble_score: 0,
      sentiment_label: 'neutral',
      confidence_score: 0
  };

  const threatClassification = classifyThreat(tweet, sentiment);

  tweet.sentiment = sentiment;
  tweet.threat = threatClassification;
  analyzedItems.push({ json: tweet });
}

function classifyThreat(tweet, sentiment) {
  let score = 0; 
  let matchedKeywords = []; 
  let threatType = 'general';

  const rawText = tweet.text_content || tweet.text || ''; 
  const text = rawText.toLowerCase();

  // Check Critical
  Object.entries(criticalKeywords).forEach(([kw, points]) => {
    if (text.includes(kw)) { score += points; matchedKeywords.push(kw); threatType = 'critical_security_incident'; }
  });

  // Check High
  Object.entries(highKeywords).forEach(([kw, points]) => {
    if (text.includes(kw)) { score += points; matchedKeywords.push(kw); if(threatType === 'general') threatType = 'high_threat'; }
  });

  // Check Medium
  Object.entries(mediumKeywords).forEach(([kw, points]) => {
    if (text.includes(kw)) { score += points; matchedKeywords.push(kw); }
  });

  // Check Low
  Object.entries(lowKeywords).forEach(([kw, points]) => {
    if (text.includes(kw)) { score += points; matchedKeywords.push(kw); }
  });

  // Sentiment Impact (Negative sentiment increases risk)
  if (sentiment.sentiment_label === 'negative' && sentiment.confidence_score > 0.6) {
    score += 10;
  }

  // Author Impact
  if (tweet.author_followers_count > 10000) score += 5;
  if (tweet.author_verified) score += 10;

  // Determine Level
  let level = 'low';
  if (score >= 50) level = 'critical';
  else if (score >= 30) level = 'high';
  else if (score >= 15) level = 'medium';

  return {
    threat_type: threatType,
    criticality_level: level,
    confidence_score: sentiment.confidence_score, // Using sentiment confidence as proxy for now
    matched_keywords: matchedKeywords,
    raw_score: score
  };
}

return analyzedItems;
